function t(key) {
  var lang = (D && D.language) || 'English';
  var code = LANG_CODE[lang];
  if (!code) return key;
  var m = TRANS[key];
  return (m && m[code]) || key;
}

function dataKey() { return 'rc_data_' + (AUTH_USER || 'local').replace(/[^a-zA-Z0-9_-]/g,''); }

function loadData() {
  try {
    var d = JSON.parse(localStorage.getItem(dataKey()));
    if (d) return validateData(d);
  } catch(e) { console.warn('loadData: corrupt localStorage entry, starting fresh', e); }
  return defaultData();
}

var _pageCache = {};
function saveData() {
  updateSchillings();
  try { localStorage.setItem(dataKey(), JSON.stringify(D)); } catch(e) { console.warn('saveData: localStorage write failed', e); showToast('Could not save to local storage. Check available space.','error'); }
  syncToFirestore();
  applyTheme();
  _pageCache = {};
  render();
  setTimeout(updateVillage, 50);
}
function saveDataSilent() {
  updateSchillings();
  try { localStorage.setItem(dataKey(), JSON.stringify(D)); } catch(e) { console.warn('saveDataSilent: localStorage write failed', e); }
  syncToFirestore();
  applyTheme();
}
function updateSchillings() {
  D.warchest = D.warchest || { schillings: 0, shields: 0, lastDayCounted: 0, lastEntryCount: 0 };
  var days = soberDays();
  var lastDay = D.warchest.lastDayCounted || 0;
  if (days > lastDay) { D.warchest.schillings += (days - lastDay) * 5; D.warchest.lastDayCounted = days; }
  D.warchest.lastEntryCount = (D.journal || []).length;
}
