function toggleTargetAddiction(type) {
  if (!D.targetAddictions) D.targetAddictions = [];
  var idx = D.targetAddictions.indexOf(type);
  var wasEmpty = D.targetAddictions.length === 0;
  if (idx >= 0) D.targetAddictions.splice(idx, 1);
  else D.targetAddictions.push(type);
  saveData();
}

function safetyPlanHTML() {
  var addictions = D.targetAddictions || [];
  var h = '<div class="card" style="border:2px solid var(--primary)"><div style="display:flex;align-items:center;gap:10px;margin-bottom:8px"><div style="width:36px;height:36px;border-radius:18px;background:var(--avatar-gertrude);display:flex;align-items:center;justify-content:center;color:#fff"><svg viewBox="0 0 16 16" width="16" height="16" fill="#fff"><path d="M8 1L3 3.5v5c0 3.5 2 5.5 5 6.5 3-1 5-3 5-6.5v-5z"/><rect x="5" y="6" width="6" height="1" rx=".2"/><line x1="8" y1="6" x2="8" y2="4" stroke="#fff" stroke-width=".8"/></svg></div><div><h3 style="margin:0;font-size:15px">Gertrude\'s Safety Plan</h3><p style="font-size:11px;color:var(--muted);margin:0">Personalized for your recovery</p></div></div>';
  if (!addictions.length) {
    h += '<p style="font-size:13px;color:var(--muted);margin-bottom:8px">Select what you are working on below, and Gertrude will create a safety plan for you.</p>';
    h += '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">';
    for (var i=0;i<ADDICTION_TYPES.length;i++) {
      h += '<button class="btn btn-sm ' + (addictions.indexOf(ADDICTION_TYPES[i]) >= 0 ? 'btn-primary' : 'btn-outline') + '" onclick="toggleTargetAddiction(\''+ADDICTION_TYPES[i]+'\')" style="font-size:11px;padding:8px">' + ADDICTION_TYPES[i] + '</button>';
    }
    h += '</div>';
  } else {
    h += '<p style="font-size:12px;color:var(--muted);margin-bottom:6px">Working on: <strong>' + addictions.join(', ') + '</strong></p>';
    for (var a=0;a<addictions.length;a++) {
      var type = addictions[a];
      var sp = SAFETY_PLANS[type] || SAFETY_PLANS['Other'];
      h += '<div style="background:var(--primary-light);padding:12px;border-radius:10px;margin-bottom:8px">';
      h += '<div style="font-weight:700;font-size:13px;margin-bottom:4px">' + type + '</div>';
      h += '<p style="font-size:12px;line-height:1.5;margin-bottom:6px">' + sp.plan + '</p>';
      h += '<div style="font-size:11px;font-weight:600;color:var(--muted);margin-bottom:3px">Your steps:</div>';
      for (var s=0;s<sp.steps.length;s++) {
        h += '<div style="display:flex;align-items:center;gap:6px;padding:3px 0;font-size:12px"><span style="width:18px;height:18px;border-radius:9px;background:var(--primary);color:#fff;display:flex;align-items:center;justify-content:center;font-size:10px;flex-shrink:0">' + (s+1) + '</span>' + sp.steps[s] + '</div>';
      }
      h += '</div>';
    }
    h += '<div style="display:flex;gap:6px;margin-top:4px">';
    h += '<button class="btn btn-sm btn-outline" onclick="D.targetAddictions=[];saveData()" style="font-size:11px">Change Addictions</button>';
    if (!D.sobriety.startDate) {
      h += '<button class="btn btn-sm btn-primary" onclick="showOnboarding()" style="font-size:11px">Start Sobriety Tracker</button>';
    }
    h += '</div>';
  }
  h += '</div>';
  return h;
}

function normId(id) { return id.toLowerCase().trim(); }

async function localHash(pwd, email, salt) {
  if (!salt) { salt = Array.from(crypto.getRandomValues(new Uint8Array(16))); }
  var enc = new TextEncoder();
  var hash = await crypto.subtle.digest('SHA-256', enc.encode('rc:' + email.toLowerCase() + ':' + pwd + ':' + salt.join(',')));
  var h = Array.from(new Uint8Array(hash)).map(function(b){return b.toString(16).padStart(2,'0')}).join('');
  return { hash: h, salt: salt };
}

function handleAuth() {
  var email = document.getElementById('si-email');
  var password = document.getElementById('si-password');
  var error = document.getElementById('si-error');
  if (!email || !email.value || !email.value.includes('@')) { alert(t('Enter a valid email.')); return; }
  if (!password || !password.value || password.value.length < 4) { alert(t('Password must be at least 4 characters.')); return; }
  if (error) error.textContent = '';
  var isSignUp = SIGN_IN_MODE === 'up';
  var emailStr = email.value.trim();
  if (isSignUp) {
    firebase.auth().createUserWithEmailAndPassword(emailStr, password.value)
      .catch(function(err) {
        if (error) error.textContent = err.message;
      });
  } else {
    firebase.auth().signInWithEmailAndPassword(emailStr, password.value)
      .catch(function(err) {
        if (error) error.textContent = err.message;
      });
  }
}
function signOut() {
  firebase.auth().signOut().catch(function(e){ console.warn(e); showToast('Something went wrong','error'); });
  localStorage.removeItem('rc_user');
  AUTH_USER = '';
  AUTH_EMAIL = '';
  D = defaultData();
  document.body.classList.remove('logged-in');
  showSignIn();
}
// ====== URL ACTION HANDLER (for manifest shortcuts) ======
function handleUrlAction() {
  var params = new URLSearchParams(window.location.search);
  var action = params.get('action');
  if (!action) return;
  // Wait for auth and render before handling action
  var check = function() {
    if (typeof goTo !== 'function' || typeof startBreathe !== 'function') { setTimeout(check, 200); return; }
    if (action === 'journal') { setTimeout(function(){ goTo('journal') }, 600); }
    else if (action === 'breathe') { setTimeout(function(){ startBreathe() }, 600); }
    else if (action === 'sos') { setTimeout(function(){ showSOS() }, 600); }
    else if (action === 'mood') { setTimeout(function(){ goTo('track') }, 600); }
  };
  check();
}
// Call after auth is set up
if (AUTH_USER) { setTimeout(handleUrlAction, 1000); }

